package com.fortinet.nac.ingestion.consumer.orchestrator;

import com.fortinet.nac.common.Constants;
import com.fortinet.nac.common.dto.IngestionRequest;
import com.fortinet.nac.common.redis.DistributedLock;
import com.fortinet.nac.common.util.StatusOr;
import com.fortinet.nac.ingestion.consumer.handler.*;
import com.fortinet.nac.ingestion.delayqueue.RedisDelayQueueUtil;
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.ingestion.service.EntityService;
import com.fortinet.nac.ingestion.util.EntityCache;
import com.fortinet.nac.ingestion.util.RedisUtil;

import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Component;


@Slf4j
@Component
@RequiredArgsConstructor
public class IngestionOrchestrator {

    private final EntityCache entityCache;
    private final EntityService entityService;
    private final DistributedLock distributedLock;
    private final RedisDelayQueueUtil redisDelayQueueUtil;

    private final NewEntityHandler newEntityHandler;
    private final CachedExistingEntityHandler cachedExistingEntityHandler;
    private final DbExistingEntityHandler dbExistingEntityHandler;

    private static final int MAX_REQUEUE = 5;
    private static final long INITIAL_BACKOFF_SEC = 2;

    public StatusOr<Entity> process(IngestionRequest req) {

        String existKey = RedisUtil.getExistKey(req);

        // 1. query cache
        Long cachedId = entityCache.getCachedEntityId(existKey);
        if (cachedId != null) {
            log.info("Entity cache HIT for key={}", existKey);
            return cachedExistingEntityHandler.handle(req, cachedId);
        }
        log.info("Entity cache MISS for key={}", existKey);

        // 2. since cache not hit, acquire creation lock
        String createLockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_CREATE_LOCK_PREFIX, req);
        boolean lock = distributedLock.tryLock(createLockKey, Constants.RedisKeys.ENTITY_CREATE_LOCK_TTL);
        if (!lock) {
            // No need to spin-retry the createLock; contention is caused by concurrency,
            // not a transient glitch that will clear shortly.
            return handleLockCreateKeyFailure(req);
        }

        try {
            // 3. DB lookup
            Entity dbEntity = entityService.getEntity(req);
            log.info("Target entity {} in Entity DB", dbEntity == null ? "not found" : "found");
            if (dbEntity != null) {
                try {
                    entityCache.cacheEntityId(existKey, dbEntity.getId(), Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
                } catch (Exception ex) {
                    log.warn("Failed to cache entityId, degrade to DB lookup next time. key={}, entityId={}, err={}",
                            existKey, dbEntity.getId(), ex.toString());
                }
                return dbExistingEntityHandler.handle(req, dbEntity.getId());
            }

            // 4. create new Entity
            return newEntityHandler.handle(req);
        } finally {
            distributedLock.unLock(createLockKey);
        }
    }

    private StatusOr<Entity> handleLockCreateKeyFailure(IngestionRequest req) {

        int retryCount = req.getRequeueCount();

        // exceed max retry
        if (retryCount >= MAX_REQUEUE) {
            log.error("Too many requeue (retry={}) for req={}, treat as failed", retryCount, req);
            return StatusOr.error(Constants.BusinesCode.ACQUIRE_CREATE_LOCK_FAILURE,
                    "too many requeue for create lock");
        }

        long delaySeconds = INITIAL_BACKOFF_SEC << retryCount; // 2,4,8,16,32
        long delayMillis = delaySeconds * 1000;

        retryCount++;
        req.setRequeueCount(retryCount);

        // send delayed msg
        try {
            redisDelayQueueUtil.enqueueWithDelay(req, delayMillis);
        } catch (Exception ex) {
            log.error("Failed to enqueue delay queue, consumer will retry. err={}", ex.toString());
            // let consumer retry
            return StatusOr.error(Constants.BusinesCode.INTERNAL_ERROR, "delay enqueue failed");
        }

        log.warn("Requeue request due to lock conflict, retry={}: {}", retryCount, req);
        return StatusOr.error(Constants.BusinesCode.ACQUIRE_CREATE_LOCK_FAILURE, "create lock fail");
    }
}

