package com.fortinet.nac.ingestion.util;

import com.fortinet.nac.common.Constants;
import com.fortinet.nac.common.dto.IngestionRequest;
import com.fortinet.nac.common.enums.EntityType;
import com.fortinet.nac.ingestion.entity.Entity;

public class RedisUtil {

    public static String getEntityLockKey(String redisKeyPrefix, IngestionRequest req) {
        if (req == null) {
            throw new IllegalArgumentException("IngestionRequest cannot be null");
        }

        String entityType = req.getEntityType();
        String hostId = req.getHostId();
        String userId = req.getUserId();
        String adapterId = req.getAdapterId();

        if (entityType == null) {
            throw new IllegalArgumentException("entityType cannot be null");
        }

        // HOST type
        if (entityType.equalsIgnoreCase(EntityType.HOST.toString())) {
            if (hostId == null || hostId.isEmpty()) {
                throw new IllegalArgumentException("hostId is required for HOST type");
            }
            if (adapterId == null || adapterId.isEmpty()) {
                throw new IllegalArgumentException("adapterId is required for HOST type");
            }
            return redisKeyPrefix + hostId + "_" + adapterId;
        }

        // USER_HOST_BINDING type
        else if (entityType.equalsIgnoreCase(EntityType.USER_HOST_BINDING.toString())) {
            if (hostId == null || hostId.isEmpty()) {
                throw new IllegalArgumentException("hostId is required for USER_HOST_BINDING type");
            }
            if (adapterId == null || adapterId.isEmpty()) {
                throw new IllegalArgumentException("adapterId is required for USER_HOST_BINDING type");
            }
            if (userId == null || userId.isEmpty()) {
                throw new IllegalArgumentException("userId is required for USER_HOST_BINDING type");
            }

            return redisKeyPrefix + hostId + "_" + adapterId + "_" + userId;
        }

        throw new IllegalArgumentException("Unsupported entityType: " + entityType);
    }

    public static String getEntityProcessLockKey(Entity e) {
        return getEntityProcessLockKey(e.getType(), e.getHostId(), e.getAdapterId(), e.getUserId());
    }

    public static String getEntityProcessLockKey(EntityType type, String hostId, String adapterId, String userId) {
        if (EntityType.USER_HOST_BINDING.equals(type)) {
            return Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX + hostId + "_" + adapterId + "_" + userId;
        }
        return Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX + hostId + "_" + adapterId;
    }

    public static String getExistKey(IngestionRequest req) {
        if (req.getEntityType().equals("HOST")) {
            if (req.getAdapterId() == null || req.getAdapterId().isEmpty()) {
                throw new IllegalArgumentException("adapterId is required for HOST type");
            }
            return Constants.RedisKeys.ENTITY_EXIST_KEY_PREFIX + req.getHostId() + "_" + req.getAdapterId();
        }
        // USER_HOST_BINDING
        return Constants.RedisKeys.ENTITY_EXIST_KEY_PREFIX
                + req.getHostId() + "_" + req.getAdapterId() + "_" + req.getUserId();
    }
}

